import{_ as s,o as e,c as n,ai as l}from"./chunks/framework.CsYGeNYI.js";const h=JSON.parse('{"title":"Linux 应用","description":"","frontmatter":{"read_when":["查找 Linux 配套应用状态时","规划平台覆盖或贡献时"],"summary":"Linux 支持 + 配套应用状态","title":"Linux 应用","x-i18n":{"generated_at":"2026-02-03T07:52:18Z","model":"claude-opus-4-5","provider":"pi","source_hash":"a9bbbcecf2fd522a2f5ac8f3b9068febbc43658465bfb9276bff6c3e946789d2","source_path":"platforms/linux.md","workflow":15}},"headers":[],"relativePath":"zh-CN/platforms/linux.md","filePath":"zh-CN/platforms/linux.md","lastUpdated":1771906665000}'),i={name:"zh-CN/platforms/linux.md"};function p(t,a,r,o,d,c){return e(),n("div",null,[...a[0]||(a[0]=[l(`<h1 id="linux-应用" tabindex="-1"><a class="header-anchor" href="#linux-应用">#</a> Linux 应用</h1><p>Gateway 网关在 Linux 上完全支持。<strong>Node 是推荐的运行时</strong>。 不推荐 Bun 用于 Gateway 网关（WhatsApp/Telegram 存在 bug）。</p><p>原生 Linux 配套应用已在计划中。如果你想帮助构建，欢迎贡献。</p><h2 id="新手快速路径-vps" tabindex="-1"><a class="header-anchor" href="#新手快速路径-vps">#</a> 新手快速路径（VPS）</h2><ol><li>安装 Node 22+</li><li><code>npm i -g opensoul@latest</code></li><li><code>opensoul onboard --install-daemon</code></li><li>从你的笔记本电脑：<code>ssh -N -L 18789:127.0.0.1:18789 &lt;user&gt;@&lt;host&gt;</code></li><li>打开 <code>http://127.0.0.1:18789/</code> 并粘贴你的令牌</li></ol><p>分步 VPS 指南：<a href="/docs/install/exe-dev">exe.dev</a></p><h2 id="安装" tabindex="-1"><a class="header-anchor" href="#安装">#</a> 安装</h2><ul><li><a href="/docs/start/getting-started">入门指南</a></li><li><a href="/docs/install/updating">安装与更新</a></li><li>可选流程：<a href="/docs/install/bun">Bun（实验性）</a>、<a href="/docs/install/nix">Nix</a>、<a href="/docs/install/docker">Docker</a></li></ul><h2 id="gateway-网关" tabindex="-1"><a class="header-anchor" href="#gateway-网关">#</a> Gateway 网关</h2><ul><li><a href="/docs/gateway/index">Gateway 网关运行手册</a></li><li><a href="/docs/gateway/configuration">配置</a></li></ul><h2 id="gateway-网关服务安装-cli" tabindex="-1"><a class="header-anchor" href="#gateway-网关服务安装-cli">#</a> Gateway 网关服务安装（CLI）</h2><p>使用以下任一方式：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>opensoul onboard --install-daemon</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>或：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>opensoul gateway install</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>或：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>opensoul configure</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>出现提示时选择 <strong>Gateway service</strong>。</p><p>修复/迁移：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>opensoul doctor</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="系统控制-systemd-用户单元" tabindex="-1"><a class="header-anchor" href="#系统控制-systemd-用户单元">#</a> 系统控制（systemd 用户单元）</h2><p>OpenSoul 默认安装 systemd <strong>用户</strong>服务。对于共享或常驻服务器使用<strong>系统</strong> 服务。完整的单元示例和指南 在 <a href="/docs/gateway/index">Gateway 网关运行手册</a> 中。</p><p>最小设置：</p><p>创建 <code>~/.config/systemd/user/opensoul-gateway[-&lt;profile&gt;].service</code>：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Unit]</span></span>
<span class="line"><span>Description=OpenSoul Gateway (profile: &lt;profile&gt;, v&lt;version&gt;)</span></span>
<span class="line"><span>After=network-online.target</span></span>
<span class="line"><span>Wants=network-online.target</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[Service]</span></span>
<span class="line"><span>ExecStart=/usr/local/bin/opensoul gateway --port 18789</span></span>
<span class="line"><span>Restart=always</span></span>
<span class="line"><span>RestartSec=5</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[Install]</span></span>
<span class="line"><span>WantedBy=default.target</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p>启用它：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>systemctl --user enable --now opensoul-gateway[-&lt;profile&gt;].service</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div>`,27)])])}const b=s(i,[["render",p]]);export{h as __pageData,b as default};
